import SwiftUI
struct DebugView: View { let debug: DebugService; var body: some View { List { Section("Timer") { LabeledContent("Memory Time", value: debug.memoryTime.readingDisplay); LabeledContent("Persisted Time", value: debug.persistedTime.readingDisplay); LabeledContent("Merged Time", value: debug.mergedTime.readingDisplay); LabeledContent("Current Session", value: debug.currentSession.readingDisplay); LabeledContent("Timer Running", value: debug.timerRunning ? "Yes" : "No"); LabeledContent("Last Merge Rule", value: debug.lastMergeRule.rawValue) }; Section("Lifecycle, Storage, and Timer Events") { if debug.events.isEmpty { Text("No events recorded.").foregroundStyle(.secondary) }; ForEach(debug.events) { event in VStack(alignment: .leading) { HStack { Text(event.kind.rawValue.capitalized).font(.caption.weight(.semibold)); Spacer(); Text(event.date, style: .time).font(.caption).foregroundStyle(.secondary) }; Text(event.message).font(.subheadline) } } } }.navigationTitle("Debug") } }
